public static void main(Args _args)
{
    CustInvoiceJour custInvoiceJour;
    str             customerName;
    int             recordsUpdated = 0;
    int             batchSize = 500; 

    info("Starting the optimized script to update DeliveryName on CustInvoiceJour for company o001...");

    changecompany('o001')
    {

        ttsbegin;

        while select forupdate custInvoiceJour
            where custInvoiceJour.OrderAccount != ''
        {

            customerName = CustTable::find(custInvoiceJour.OrderAccount).name();


            if (customerName && custInvoiceJour.DeliveryName != customerName)
            {
                custInvoiceJour.DeliveryName = customerName;
                custInvoiceJour.update();

                recordsUpdated++;


                if ((recordsUpdated mod batchSize) == 0)
                {
                    ttscommit;
                    ttsbegin; // Start a fresh transaction for the next batch
                }
            }
        }


        ttscommit;
    }

    info(strFmt("Script execution completed cleanly. Successfully updated %1 records.", recordsUpdated));
}
